UPDATE news SET description = 'Transferência Eletrônica de Fundos (TEF) é um sistema de pagamento eletrônico que permite a transferência de valores entre contas bancárias de forma rápida e segura. Descubra como o TEF funciona e por que é essencial para o seu negócio.' WHERE id = 1;
UPDATE news SET description = 'Entenda as principais diferenças entre TEF e maquininha tradicional. TEF oferece maior segurança, menores taxas e melhor controle de transações. Saiba por que grandes empresas estão migrando para TEF.' WHERE id = 2;
UPDATE news SET description = 'A segurança é fundamental em transações eletrônicas. Conheça os protocolos de criptografia, autenticação de dois fatores e as melhores práticas para proteger seus dados financeiros.' WHERE id = 3;
UPDATE news SET description = 'Acompanhe as principais tendências do mercado financeiro em 2024. Desde a adoção de criptomoedas até a inteligência artificial em análise de risco, o setor está em constante evolução.' WHERE id = 4;
UPDATE news SET description = 'TEF não é apenas um método de pagamento, é uma ferramenta para aumentar vendas. Com transações mais rápidas e confiáveis, seus clientes têm mais confiança em comprar. Veja como implementar TEF no seu negócio.' WHERE id = 5;

